-
-            // Setup WASI args
-            var wasi_args_daemon: [64][*c]const u8 = undefined;
-            var wasi_argc_daemon: usize = 0;
-
-            var script_path_z: [4096]u8 = undefined;
-            @memcpy(script_path_z[0..script_path.len], script_path);
-            script_path_z[script_path.len] = 0;
