-fn hostAddStdin(data: ?*anyopaque, call_ctx: ?*const c.WasmEdge_CallingFrameContext, params: [*c]const c.WasmEdge_Value, returns: [*c]c.WasmEdge_Value) callconv(.c) c.WasmEdge_Result {
